\begin{align}
\mathbf{H}^{(f)}, \mathbf{S}_{blocks}^{(f)} &= \text{SSD}(\mathbf{S}_{\text{forward}}; \boldsymbol{\theta}, \text{return\_states=True}) \label{eq:forward_coupling}\\
\mathbf{H}^{(b)}, \mathbf{S}_{blocks}^{(b)} &= \text{SSD}(\mathbf{S}_{\text{backward}}; \boldsymbol{\theta}, \text{return\_states=True}) \label{eq:backward_coupling}
\end{align}

